import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "./Header.css";

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [user, setUser] = useState(null);
  const [userMenuOpen, setUserMenuOpen] = useState(false);

  const searchRef = useRef(null);
  const userRef = useRef(null);
  const navigate = useNavigate();

  const decodeToken = (token) => {
    try {
      const base64Url = token.split(".")[1];
      const base64 = base64Url.replace(/-/g, "+").replace(/_/g, "/");
      const jsonPayload = decodeURIComponent(
        atob(base64)
          .split("")
          .map((c) => "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2))
          .join("")
      );
      return JSON.parse(jsonPayload);
    } catch (err) {
      return null;
    }
  };

  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) {
      const payload = decodeToken(token);
      if (payload) {
        // თუ სურათი ცარიელია ან http-ითაა, გავაკეთოთ https
        let photo = payload.photo || "";
        if (photo && photo.startsWith("http:")) {
          photo = photo.replace("http:", "https:");
        }
        payload.photo = photo || "/images/default.png";
        setUser(payload);
      }
    }
  }, []);

  // inactivity logout
  useEffect(() => {
    let timer;

    const resetTimer = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        localStorage.removeItem("auth_token");
        setUser(null);
        navigate("/register");
      }, 30 * 60 * 1000); // 30 წუთი
    };

    window.addEventListener("mousemove", resetTimer);
    window.addEventListener("keydown", resetTimer);

    resetTimer();

    return () => {
      clearTimeout(timer);
      window.removeEventListener("mousemove", resetTimer);
      window.removeEventListener("keydown", resetTimer);
    };
  }, [navigate]);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) {
        setSearchOpen(false);
      }
      if (userRef.current && !userRef.current.contains(e.target)) {
        setUserMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    const query = searchQuery.trim();
    if (!query) return;
    navigate(`/articles?q=${encodeURIComponent(query)}`);
    setSearchOpen(false);
    setSearchQuery("");
    setMenuOpen(false);
  };

  const handleSignOut = () => {
    localStorage.removeItem("auth_token");
    setUser(null);
    setUserMenuOpen(false);
    navigate("/register");
  };

  const handleUserIconClick = () => {
    setUserMenuOpen((p) => !p);
    setSearchOpen(false);
    setMenuOpen(false);
  };

  return (
    <header className="header">
      {/* Logo */}
      <div className="logo">
        <NavLink to="/" onClick={() => setMenuOpen(false)}>
          <img src="/lo.png" alt="MBTI Logo" />
        </NavLink>
      </div>

      {/* Navigation */}
      <nav className={`nav ${menuOpen ? "open" : ""}`}>
        <ul>
          <li>
            <NavLink to="/" end onClick={() => setMenuOpen(false)}>
              მთავარი
            </NavLink>
          </li>
          <li>
            <NavLink to="/mbti-dimensions" onClick={() => setMenuOpen(false)}>
              MBTI განზომილებები
            </NavLink>
          </li>
          <li>
            <NavLink to="/articles" onClick={() => setMenuOpen(false)}>
              მიმოხილვები
            </NavLink>
          </li>
          <li>
            <NavLink to="/start-test" onClick={() => setMenuOpen(false)}>
              დაიწყე ტესტი
            </NavLink>
          </li>
        </ul>
      </nav>

      {/* Actions */}
      <div className="header-actions" ref={searchRef}>
        <button
          className="search-toggle"
          onClick={() => {
            setSearchOpen((p) => !p);
            setMenuOpen(false);
          }}
        >
          <img src="/search.png" alt="ძებნა" className="search-icon" />
        </button>

        {searchOpen && (
          <form className="search-form" onSubmit={handleSearchSubmit}>
            <input
              type="text"
              placeholder="ძებნა საიტზე..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              autoFocus
            />
            <button type="submit">ძიება</button>
          </form>
        )}

        {!user ? (
          <NavLink to="/register" className="mobile-signin">
            Sign In
          </NavLink>
        ) : (
          <div
            ref={userRef}
            className="header-user-wrapper"
            onClick={handleUserIconClick}
          >
            <div className="header-user">
              <img
                src={user.photo}
                alt={user.name}
                className="header-user-photo"
                onError={(e) => (e.target.src = "/images/default.png")}
              />
            </div>

            {userMenuOpen && (
              <div className="user-dropdown">
                <span className="dropdown-user-email">{user.email}</span>
                <button onClick={() => navigate("/profile")}>Profile</button>
                <button onClick={handleSignOut}>Sign Out</button>
              </div>
            )}
          </div>
        )}
      </div>

      <button
        className={`menu-toggle ${menuOpen ? "open" : ""}`}
        onClick={() => setMenuOpen((p) => !p)}
        aria-label="მენიუ"
      >
        <span></span>
        <span></span>
        <span></span>
      </button>
    </header>
  );
}
